#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)b - *(int*)a);
}
int* maxCombinations(int* nums1, int nums1Size, int* nums2, int nums2Size, int k, int* returnSize) {
    int* allSums = (int*)malloc(nums1Size * nums2Size * sizeof(int));
    int index = 0;
    for (int i = 0; i < nums1Size; i++) {
        for (int j = 0; j < nums2Size; j++) {
            allSums[index++] = nums1[i] + nums2[j];
        }
    }
    qsort(allSums, nums1Size * nums2Size, sizeof(int), compare);
    int* result = (int*)malloc(k * sizeof(int));
    for (int i = 0; i < k; i++) {
        result[i] = allSums[i];
    }
    *returnSize = k;
    free(allSums);
    return result;
}

