#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    vector<int> maxCombinations(vector<int>& nums1, vector<int>& nums2, int k) {
        vector<int> allSums;
        for (int i = 0; i < nums1.size(); i++) {
            for (int j = 0; j < nums2.size(); j++) {
                allSums.push_back(nums1[i] + nums2[j]);
            }
        }
        sort(allSums.begin(), allSums.end(), greater<int>());
        vector<int> result(allSums.begin(), allSums.begin() + k);
        return result;
    }
};

code.Java:
import java.util.*;
class Solution {
    public int[] maxCombinations(int[] nums1, int[] nums2, int k) {
        List<Integer> allSums = new ArrayList<>();
        for (int i = 0; i < nums1.length; i++) {
            for (int j = 0; j < nums2.length; j++) {
                allSums.add(nums1[i] + nums2[j]);
            }
        }
        Collections.sort(allSums, Collections.reverseOrder());
        int[] result = new int[k];
        for (int i = 0; i < k; i++) {
            result[i] = allSums.get(i);
        }
        return result;
    }
}

