class Solution {
    maxCombinations(nums1, nums2, k) {
        let allSums = [];
        for (let i = 0; i < nums1.length; i++) {
            for (let j = 0; j < nums2.length; j++) {
                allSums.push(nums1[i] + nums2[j]);
            }
        }
        allSums.sort((a, b) => b - a);
        return allSums.slice(0, k);
    }
}

